import axios from "axios";

export const fetchPatients = async () => {
  const res = await axios.get("/api/patients");
  return res.data;
};

export const fetchDoctors = async () => {
  const res = await axios.get("/api/doctors");
  return res.data;
};

export const createAppointment = async (data) => {
  const res = await axios.post("/api/appointments", data);
  return res.data;
};

export const updateAppointmentStatus = async (id, status) => {
  const res = await axios.patch(`/api/appointments/${id}/status`, { status });
  return res.data;
};

export const fetchAppointmentsByPatient = async (patientId) => {
  const res = await axios.get(`/api/appointments/patient/${patientId}`);
  return res.data;
};
